543→
544→                    inB1 = *__SIMD64(pB);
545→                    pB += in_tensor_ch;
546→                    opB = *__SIMD64(pB);
547→                    pB += in_tensor_ch;
548→                    inB2 = NDS_DSP_PKTT16(opB, inB1);
549→                    inB1 = NDS_DSP_PKBB16(opB, inB1);
550→
551→                    inA1 = *__SIMD64(pA);
552→                    pA += in_tensor_ch;
553→                    opB = *__SIMD64(pA);
554→                    pA += in_tensor_ch;
555→                    inA2 = NDS_DSP_PKTT16(opB, inA1);
556→                    inA1 = NDS_DSP_PKBB16(opB, inA1);
557→
558→                    opA = NDS_DSP_SUNPKD820(inA1);
559→                    opB = NDS_DSP_SUNPKD820(inB1);
560→                    sum = NDS_DSP_KMADA(sum, opA, opB);
561→
562→                    opA = NDS_DSP_SUNPKD831(inA1);
563→                    opB = NDS_DSP_SUNPKD831(inB1);
564→                    sum2 = NDS_DSP_KMADA(sum2, opA, opB);
565→
566→                    opA = NDS_DSP_SUNPKD820(inA2);
567→                    opB = NDS_DSP_SUNPKD820(inB2);
568→                    sum3 = NDS_DSP_KMADA(sum3, opA, opB);
569→
570→                    opA = NDS_DSP_SUNPKD831(inA2);
571→                    opB = NDS_DSP_SUNPKD831(inB2);
572→                    sum4 = NDS_DSP_KMADA(sum4, opA, opB);
573→
574→                    colCnt--;
575→                }
576→
577→                long sum5 = (q31_t)(sum >> 32);
578→                long sum6 = (q31_t)(sum2 >> 32);
579→                long sum7 = (q31_t)(sum3 >> 32);
580→                long sum8 = (q31_t)(sum4 >> 32);
581→                sum  = (q31_t)sum;
582→                sum2 = (q31_t)sum2;
583→                sum3 = (q31_t)sum3;
584→                sum4 = (q31_t)sum4;
585→
586→                sum  += *pBias++;
587→                sum2 += *pBias++;
588→                sum3 += *pBias++;
589→                sum4 += *pBias++;
590→                sum5 += *pBias++;
591→                sum6 += *pBias++;
592→                sum7 += *pBias++;
593→                sum8 += *pBias++;
594→
595→                colCnt = (ker_dim_x * ker_dim_y) & 0x1;
596→                if (colCnt)
597→                {
598→                    sum  += *pA * *pB;
599→                    sum2 += *(pA+1) * *(pB+1);
600→                    sum3 += *(pA+2) * *(pB+2);
601→                    sum4 += *(pA+3) * *(pB+3);
602→                    sum5 += *(pA+4) * *(pB+4);
603→                    sum6 += *(pA+5) * *(pB+5);
604→                    sum7 += *(pA+6) * *(pB+6);
605→                    sum8 += *(pA+7) * *(pB+7);
606→                }
607→
608→                sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
609→                sum2 = (sum2 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
610→                sum3 = (sum3 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
611→                sum4 = (sum4 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
612→                sum5 = (sum5 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
613→                sum6 = (sum6 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
614→                sum7 = (sum7 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
615→                sum8 = (sum8 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
616→
617→                *pOut++ = NDS_DSP_SATS((sum  >> post_rshift), 8);
618→                *pOut++ = NDS_DSP_SATS((sum2 >> post_rshift), 8);
619→                *pOut++ = NDS_DSP_SATS((sum3 >> post_rshift), 8);
620→                *pOut++ = NDS_DSP_SATS((sum4 >> post_rshift), 8);
621→                *pOut++ = NDS_DSP_SATS((sum5 >> post_rshift), 8);
622→                *pOut++ = NDS_DSP_SATS((sum6 >> post_rshift), 8);
623→                *pOut++ = NDS_DSP_SATS((sum7 >> post_rshift), 8);
624→                *pOut++ = NDS_DSP_SATS((sum8 >> post_rshift), 8);
625→
626→                rowCnt--;
627→            }
628→
629→            if ((out_tensor_ch & 0x7) > 3)
630→            {
631→                long sum  = *pBias++;
632→                long sum2 = *pBias++;
633→                long sum3 = *pBias++;
634→                long sum4 = *pBias++;
635→
636→                long  colCnt = (ker_dim_x * ker_dim_y) >> 1;
637→                q7_t     *pB = colBuffer + row_shift;
638→                const q7_t *pA = ker_weight + row_shift;
639→                row_shift += 4;
640→
641→                while (colCnt)
642→                {
643→                    long     inA1, inA2, inB1, inB2, opA, opB;
644→
645→                    inB1 = *__SIMD32(pB);
646→                    pB += in_tensor_ch;
647→                    opB = *__SIMD32(pB);
648→                    pB += in_tensor_ch;
649→                    inB2 = NDS_DSP_PKTT16(opB, inB1);
650→                    inB1 = NDS_DSP_PKBB16(opB, inB1);
651→
652→                    inA1 = *__SIMD32(pA);
653→                    pA += in_tensor_ch;
654→                    opB = *__SIMD32(pA);
655→                    pA += in_tensor_ch;
656→                    inA2 = NDS_DSP_PKTT16(opB, inA1);
657→                    inA1 = NDS_DSP_PKBB16(opB, inA1);
658→
659→                    opA = NDS_DSP_SUNPKD820(inA1);
660→                    opB = NDS_DSP_SUNPKD820(inB1);
661→                    sum = NDS_DSP_KMADA(sum, opA, opB);
662→
663→                    opA = NDS_DSP_SUNPKD831(inA1);
664→                    opB = NDS_DSP_SUNPKD831(inB1);
665→                    sum2 = NDS_DSP_KMADA(sum2, opA, opB);
666→
667→                    opA = NDS_DSP_SUNPKD820(inA2);
668→                    opB = NDS_DSP_SUNPKD820(inB2);
669→                    sum3 = NDS_DSP_KMADA(sum3, opA, opB);
670→
671→                    opA = NDS_DSP_SUNPKD831(inA2);
672→                    opB = NDS_DSP_SUNPKD831(inB2);
673→                    sum4 = NDS_DSP_KMADA(sum4, opA, opB);
674→
675→                    colCnt--;
676→                }
677→
678→                colCnt = (ker_dim_x * ker_dim_y) & 0x1;
679→                if (colCnt)
680→                {
681→                    sum  += *pA * *pB;
682→                    sum2 += *(pA+1) * *(pB+1);
683→                    sum3 += *(pA+2) * *(pB+2);
684→                    sum4 += *(pA+3) * *(pB+3);
685→                }
686→
687→                q31_t out1 = sum;
688→                q31_t out2 = sum2;
689→                q31_t out3 = sum3;
690→                q31_t out4 = sum4;
691→
692→                out1 = (out1 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
693→                out2 = (out2 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
694→                out3 = (out3 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
695→                out4 = (out4 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
696→
697→                *pOut++ = NDS_DSP_SATS((out1 >> post_rshift), 8);
698→                *pOut++ = NDS_DSP_SATS((out2 >> post_rshift), 8);
699→                *pOut++ = NDS_DSP_SATS((out3 >> post_rshift), 8);
700→                *pOut++ = NDS_DSP_SATS((out4 >> post_rshift), 8);
701→
702→                rowCnt--;
703→            }
704→
705→            rowCnt = out_tensor_ch & 0x3;
706→            while (rowCnt)
707→            {
708→                q7_t     *pB = colBuffer + row_shift;
709→                const q7_t *pA = ker_weight + row_shift;
710→                q31_t     sum = *pBias++;
711→                long  colCnt = (ker_dim_x * ker_dim_y);
712→                row_shift += 1;
713→
714→                while (colCnt)
715→                {
716→                    q7_t      A1 = *pA;
717→                    q7_t      B1 = *pB;
718→                    pA += in_tensor_ch;
719→                    pB += in_tensor_ch;
720→                    sum += A1 * B1;
721→                    colCnt--;
722→                }
723→                sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
724→                *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
725→                rowCnt--;
726→            }
727→#else
728→            rowCnt = out_tensor_ch >> 2;
729→            while (rowCnt)
730→            {
731→                q31_t sum =  *pBias++;
732→                q31_t sum2 = *pBias++;
733→                q31_t sum3 = *pBias++;
734→                q31_t sum4 = *pBias++;
735→                q7_t     *pB = colBuffer + row_shift;
736→                const q7_t *pA = ker_weight + row_shift;
737→                long  colCnt = (ker_dim_x * ker_dim_y) >> 1;
738→                row_shift += 4;
739→
740→                while (colCnt)
741→                {
742→                    q31_t     inA1, inA2, inB1, inB2, opA, opB;
743→
744→                    inB1 = *__SIMD32(pB);
745→                    pB += in_tensor_ch;
746→                    opB = *__SIMD32(pB);
747→                    pB += in_tensor_ch;
748→                    inB2 = NDS_DSP_PKTT16(opB, inB1);
749→                    inB1 = NDS_DSP_PKBB16(opB, inB1);
750→
751→                    inA1 = *__SIMD32(pA);
752→                    pA += in_tensor_ch;
753→                    opB = *__SIMD32(pA);
754→                    pA += in_tensor_ch;
755→                    inA2 = NDS_DSP_PKTT16(opB, inA1);
756→                    inA1 = NDS_DSP_PKBB16(opB, inA1);
757→
758→                    opA = NDS_DSP_SUNPKD820(inA1);
759→                    opB = NDS_DSP_SUNPKD820(inB1);
760→                    sum = NDS_DSP_KMADA(sum, opA, opB);
761→
762→                    opA = NDS_DSP_SUNPKD831(inA1);
763→                    opB = NDS_DSP_SUNPKD831(inB1);
764→                    sum2 = NDS_DSP_KMADA(sum2, opA, opB);
765→
766→                    opA = NDS_DSP_SUNPKD820(inA2);
767→                    opB = NDS_DSP_SUNPKD820(inB2);
768→                    sum3 = NDS_DSP_KMADA(sum3, opA, opB);
769→
770→                    opA = NDS_DSP_SUNPKD831(inA2);
771→                    opB = NDS_DSP_SUNPKD831(inB2);
772→                    sum4 = NDS_DSP_KMADA(sum4, opA, opB);
773→                    colCnt--;
774→                }
775→
776→                if (restCol)
777→                {
778→                    sum  += *pA * *pB;
779→                    sum2 += *(pA+1) * *(pB+1);
780→                    sum3 += *(pA+2) * *(pB+2);
781→                    sum4 += *(pA+3) * *(pB+3);
782→                }
783→                sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
784→                sum2 = (sum2 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
785→                sum3 = (sum3 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
786→                sum4 = (sum4 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
787→                *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
788→                *pOut++ = NDS_DSP_SATS((sum2 >> post_rshift), 8);
789→                *pOut++ = NDS_DSP_SATS((sum3 >> post_rshift), 8);
790→                *pOut++ = NDS_DSP_SATS((sum4 >> post_rshift), 8);
791→                rowCnt--;
792→            }
793→
794→            rowCnt = out_tensor_ch & 0x3;
795→            while (rowCnt)
796→            {
797→                q7_t     *pB = colBuffer + row_shift;
798→                const q7_t *pA = ker_weight + row_shift;
799→                q31_t     sum = *pBias++;
800→                long  colCnt = (ker_dim_x * ker_dim_y);
801→                row_shift += 1;
802→
803→                while (colCnt)
804→                {
805→                    q7_t      A1 = *pA;
806→                    q7_t      B1 = *pB;
807→                    pA += in_tensor_ch;
808→                    pB += in_tensor_ch;
809→                    sum += A1 * B1;
810→                    colCnt--;
811→                }
812→                sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
813→                *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
814→                rowCnt--;
815→            }
816→#endif
817→            // clear counter and pointers
818→            pBuffer = colBuffer;
819→        }
820→    }
821→#else
822→    int i_out_y, i_out_x, i_ch_out;
823→    int i_ker_y, i_ker_x;
824→
825→    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
826→    {
827→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
828→        {
829→            for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
830→            {
831→                int conv_out = bias[i_ch_out];
832→                for (i_ker_y = 0; i_ker_y < ker_dim_y; i_ker_y++)
833→                {
834→                    for (i_ker_x = 0; i_ker_x < ker_dim_x; i_ker_x++)
835→                    {
836→                        int in_row = stride_y * i_out_y + i_ker_y - pad_y;
837→                        int in_col = stride_x * i_out_x + i_ker_x - pad_x;
838→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
839→                        {
840→                            conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + i_ch_out] *
841→                                        ker_weight[(i_ker_y * ker_dim_x + i_ker_x) * out_tensor_ch + i_ch_out];
842→                        }
843→                    }
844→                }
845→                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
846→                out_tensor[(i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch + i_ch_out] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
847→            }
848→        }
849→    }
850→#endif
851→}
