 26→
 27→int32_t riscv_nn_conv_dw_HWC_s8_s16_s8_sym_bias(const q7_t * in_tensor,
 28→        const uint16_t in_tensor_dim,
 29→        const uint16_t in_tensor_ch,
 30→        const q7_t * ker_weight,
 31→        const uint16_t out_tensor_ch,
 32→        const uint16_t ker_dim,
 33→        const uint16_t pad,
 34→        const uint16_t stride,
 35→        const q31_t * bias,
 36→        const uint16_t pre_rshift,
 37→        const uint16_t out_scale,
 38→        const uint16_t post_rshift,
 39→        q15_t * out_tensor,
 40→        const uint16_t out_tensor_dim,
 41→        q15_t * in_tmp_buf)
 42→{
 43→#ifdef ENA_EMPTY_FUN
 44→    //empty body
 45→#else
 46→    /* do some checking here, basically in_tensor_ch == out_tensor_ch */
 47→    if (in_tensor_ch != out_tensor_ch)
 48→    {
 49→        return -1;
 50→    }
 51→
 52→#if defined(ENA_VEC_ISA) && defined(ENA_VEC_ISA_ZVQMAC) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 53→    for(long in_y = -pad, out_y = 0; out_y < out_tensor_dim; in_y += stride, out_y++)
 54→    {
 55→        long ker_y_start = MAX(0, -in_y);
 56→        for(long in_x = -pad, out_x = 0; out_x < out_tensor_dim; in_x += stride, out_x++)
 57→        {
 58→            long cur_ch = 0;
 59→            long ker_x_start = MAX(0, -in_x);
 60→            q31_t *pBias = (q31_t*)bias;
 61→
 62→            while(cur_ch < in_tensor_ch)
 63→            {
 64→                long vl;
 65→                vl = __riscv_vsetvl_e32m8(in_tensor_ch - cur_ch);
 66→                vint32m8_t vAcc = __riscv_vundefined_i32m8();
 67→                vAcc = __riscv_vle32_v_i32m8(pBias, vl);
 68→
 69→                const q7_t *input_ptr  = in_tensor + (in_y + ker_y_start) * (in_tensor_ch * in_tensor_dim) + (in_x + ker_x_start) * in_tensor_ch + cur_ch;
 70→                const q7_t *kernel_ptr = ker_weight + ker_y_start * (in_tensor_ch * ker_dim) + ker_x_start * in_tensor_ch + cur_ch;
 71→
 72→                vl = __riscv_vsetvl_e8m2(vl);
 73→                vint8m2_t vInput_i8 = __riscv_vundefined_i8m2();
 74→                vint8m2_t vKernel_i8 = __riscv_vundefined_i8m2();
 75→                for(long ker_y = ker_y_start; ker_y < MIN(ker_dim, in_tensor_dim - in_y); ++ker_y)
 76→                {
 77→                    q7_t *input_ptr2  = (q7_t*)input_ptr;
 78→                    q7_t *kernel_ptr2 = (q7_t*)kernel_ptr;
 79→
 80→                    for(long ker_x = ker_x_start; ker_x < MIN(ker_dim, in_tensor_dim - in_x); ++ker_x)
 81→                    {
 82→                        vInput_i8 = __riscv_vle8_tu(vInput_i8, input_ptr2, vl);
 83→                        vKernel_i8 = __riscv_vle8_tu(vKernel_i8, kernel_ptr2, vl);
 84→                        vAcc = __riscv_vqmacc_vv_i32m8_tu(vAcc, vInput_i8, vKernel_i8, vl);
 85→                        input_ptr2 += in_tensor_ch;
 86→                        kernel_ptr2 += in_tensor_ch;
 87→                    }
 88→
 89→                    input_ptr  += (in_tensor_ch * in_tensor_dim);
 90→                    kernel_ptr += (in_tensor_ch * ker_dim);
 91→                }
 92→
 93→                vl = __riscv_vsetvl_e32m8(vl);
 94→                vAcc = __riscv_vsra(vAcc, pre_rshift, vl);
 95→                vAcc = __riscv_vmul(vAcc, out_scale, vl);
 96→                vl = __riscv_vsetvl_e16m4(vl);
 97→                vint16m4_t vResult_i16 = __riscv_vnclip(vAcc, post_rshift, __RISCV_VXRM_RNU, vl);
 98→                __riscv_vse16(out_tensor, vResult_i16, vl);
 99→                out_tensor += vl;
100→
101→                cur_ch += vl;
102→                pBias += vl;
103→            }
104→        }
105→    }
106→#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_ISA_ZVQMAC) && (NDS_VEC_RVV_VERSION >= 100)
107→    for(long in_y = -pad, out_y = 0; out_y < out_tensor_dim; in_y += stride, out_y++)
108→    {
109→        long ker_y_start = MAX(0, -in_y);
110→        for(long in_x = -pad, out_x = 0; out_x < out_tensor_dim; in_x += stride, out_x++)
111→        {
112→            long cur_ch = 0;
113→            long ker_x_start = MAX(0, -in_x);
114→            q31_t *pBias = (q31_t*)bias;
115→
116→            while(cur_ch < in_tensor_ch)
117→            {
118→                long vl;
119→                NDS_VEC_VSETVLI(vl, in_tensor_ch - cur_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
120→                NDS_VEC_VLE32_V(NDS_VEC_V0, pBias);
121→
122→                const q7_t *input_ptr  = in_tensor + (in_y + ker_y_start) * (in_tensor_ch * in_tensor_dim) + (in_x + ker_x_start) * in_tensor_ch + cur_ch;
123→                const q7_t *kernel_ptr = ker_weight + ker_y_start * (in_tensor_ch * ker_dim) + ker_x_start * in_tensor_ch + cur_ch;
124→
125→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
126→                for(long ker_y = ker_y_start; ker_y < MIN(ker_dim, in_tensor_dim - in_y); ++ker_y)
127→                {
128→                    q7_t *input_ptr2  = (q7_t*)input_ptr;
129→                    q7_t *kernel_ptr2 = (q7_t*)kernel_ptr;
130→
131→                    for(long ker_x = ker_x_start; ker_x < MIN(ker_dim, in_tensor_dim - in_x); ++ker_x)
132→                    {
133→                        NDS_VEC_VLE8_V(NDS_VEC_V8, input_ptr2);
134→                        NDS_VEC_VLE8_V(NDS_VEC_V10, kernel_ptr2);
135→                        NDS_VEC_VQMACC_VV(NDS_VEC_V0, NDS_VEC_V10, NDS_VEC_V8);
136→                        input_ptr2 += in_tensor_ch;
137→                        kernel_ptr2 += in_tensor_ch;
138→                    }
139→
140→                    input_ptr  += (in_tensor_ch * in_tensor_dim);
141→                    kernel_ptr += (in_tensor_ch * ker_dim);
142→                }
143→
144→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
145→                NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
146→                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
147→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
148→                NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
149→                NDS_VEC_VSE16_V(NDS_VEC_V0, out_tensor);
150→                out_tensor += vl;
151→
152→                cur_ch += vl;
153→                pBias += vl;
154→            }
155→        }
156→    }
157→#elif defined(ENA_DSP_ISA)
158→    long   i_out_y, i_out_x;
159→    long   i_ker_y, i_ker_x;
160→    q7_t     *colBuffer = (q7_t *)in_tmp_buf;
161→    q7_t     *pBuffer = colBuffer;
162→    q15_t     *pOut = out_tensor;
163→    long  rowCnt;
164→    long  row_shift;
165→    const q31_t *pBias = bias;
166→
167→
168→#if !defined(ENA_DSP_ISA_64)
169→    long ker_dim2 = ker_dim * ker_dim;
170→    long colCnt2 = ker_dim2 >> 1;
171→    long restCol = ker_dim2 & 0x1;
172→#endif
173→
174→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
175→    {
176→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
177→        {
178→            /* we first do im2col here */
179→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
180→            {
181→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
182→                {
183→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
184→                    {
185→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
186→                    }
187→                    else
188→                    {
189→                        nn_dup_s8
190→                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
191→                    }
192→                    pBuffer += in_tensor_ch;
193→                }
194→            }
195→
196→            /* we will do the computation here for each channel */
197→            pBias = bias;
198→            row_shift = 0;
199→            q7_t *pB;
200→            const q7_t *pA;
201→
202→#if defined(ENA_DSP_ISA_64)
203→            rowCnt = out_tensor_ch >> 3;
204→            row_shift = 0;
205→            pBias = bias;
206→
207→            while (rowCnt)
208→            {
209→                long sum = 0;
210→                long sum2 = 0;
211→                long sum3 = 0;
212→                long sum4 = 0;
213→
214→                long  colCnt = (ker_dim * ker_dim) >> 1;
215→                pB = colBuffer + row_shift;
216→                pA = ker_weight + row_shift;
217→                row_shift += 8;
218→
219→                while (colCnt)
220→                {
221→                    long     inA1, inA2, inB1, inB2, opA, opB;
222→
223→                    inB1 = *__SIMD64(pB);
224→                    pB += in_tensor_ch;
225→                    opB = *__SIMD64(pB);
226→                    pB += in_tensor_ch;
227→                    inB2 = NDS_DSP_PKTT16(opB, inB1);
228→                    inB1 = NDS_DSP_PKBB16(opB, inB1);
229→
230→                    inA1 = *__SIMD64(pA);
231→                    pA += in_tensor_ch;
232→                    opB = *__SIMD64(pA);
233→                    pA += in_tensor_ch;
234→                    inA2 = NDS_DSP_PKTT16(opB, inA1);
235→                    inA1 = NDS_DSP_PKBB16(opB, inA1);
236→
237→                    opA = NDS_DSP_SUNPKD820(inA1);
238→                    opB = NDS_DSP_SUNPKD820(inB1);
239→                    sum = NDS_DSP_KMADA(sum, opA, opB);
240→
241→                    opA = NDS_DSP_SUNPKD831(inA1);
242→                    opB = NDS_DSP_SUNPKD831(inB1);
243→                    sum2 = NDS_DSP_KMADA(sum2, opA, opB);
244→
245→                    opA = NDS_DSP_SUNPKD820(inA2);
246→                    opB = NDS_DSP_SUNPKD820(inB2);
247→                    sum3 = NDS_DSP_KMADA(sum3, opA, opB);
248→
249→                    opA = NDS_DSP_SUNPKD831(inA2);
250→                    opB = NDS_DSP_SUNPKD831(inB2);

