 25→//// FullyConnected Functions
 26→int32_t riscv_nn_fc_s8_s8_s8_sym_bias(const q7_t * in_vec,
 27→                                    const q7_t * wt_mat,
 28→                                    const uint16_t size,
 29→                                    const uint16_t wt_row_num,
 30→                                    const uint16_t pre_rshift,
 31→                                    const uint16_t out_scale,
 32→                                    const uint16_t post_rshift,
 33→                                    const q31_t * bias,
 34→                                    q7_t * out_vec,
 35→                                    q15_t * in_tmp_buf)
 36→{
 37→#ifdef ENA_EMPTY_FUN
 38→    //empty body
 39→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
 40→    long vl;
 41→    long rowCnt = wt_row_num >> 1;
 42→    const q7_t *in_vec_bak = in_vec;
 43→    long vlenb = NDS_VEC_CSR_GET_VLENB();
 44→
 45→#if (__clang__)
 46→    register const long zero asm ("x0") = 0;
 47→#else
 48→    register const long zero asm ("x0");
 49→#endif
 50→
 51→    vl = __riscv_vsetvl_e32m1(1);
 52→    vint32m1_t vZero = __riscv_vundefined_i32m1();
 53→    vZero = __riscv_vand_tu(vZero, vZero, zero, vl);    //const zero for redsum
 54→
 55→    while(rowCnt > 0)
 56→    {
 57→        vl = __riscv_vsetvl_e32m4(size);
 58→        vint32m4_t vAcc0 = __riscv_vundefined_i32m4();
 59→        vint32m4_t vAcc1 = __riscv_vundefined_i32m4();
 60→        //clear acc
 61→        vAcc0 = __riscv_vand_tu(vAcc0, vAcc0, 0, vl);     //acc_0
 62→        vAcc1 = __riscv_vand_tu(vAcc1, vAcc1, 0, vl);     //acc_1
 63→        in_vec = in_vec_bak;
 64→        const q7_t * wt_mat2 = wt_mat + size;
 65→        long colCnt2 = size;
 66→
 67→        while(colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M4))
 68→        {
 69→            vl = __riscv_vsetvl_e8m4(colCnt2);
 70→            //load src1
 71→            vint8m4_t vIn_vec_i8 = __riscv_vle8_v_i8m4(in_vec, vl);
 72→            //load src2
 73→            vint8m4_t vWt_mat_i8 = __riscv_vle8_v_i8m4(wt_mat, vl);
 74→            vint8m4_t vWt_mat2_i8 = __riscv_vle8_v_i8m4(wt_mat2, vl);
 75→            //bump pointers and update loop counter
 76→            colCnt2 -= vl;
 77→            in_vec += vl;
 78→            wt_mat += vl;
 79→            wt_mat2 += vl;
 80→            //set the proper avl/SEW/LMUL values for vd4dot
 81→            vl >>= 2;
 82→            vl = __riscv_vsetvl_e32m4(vl);
 83→            //acc += src1 * src2
 84→            vAcc0 = __riscv_vd4dots_vv_i32m4(vAcc0, vWt_mat_i8, vIn_vec_i8, vl);
 85→            vAcc1 = __riscv_vd4dots_vv_i32m4(vAcc1, vWt_mat2_i8, vIn_vec_i8, vl);
 86→        }
 87→
 88→        //extra process for the case of vd4dot's avl is not a mutiple of 4
 89→        if(colCnt2 > 0)
 90→        {
 91→            //clean one of the dot product source
 92→            vl = __riscv_vsetvlmax_e8m4();
 93→            vint8m4_t vIn_vec_i8 = __riscv_vundefined_i8m4();
 94→            vint8m4_t vWt_mat_i8 = __riscv_vundefined_i8m4();
 95→            vint8m4_t vWt_mat2_i8 = __riscv_vundefined_i8m4();
 96→			vIn_vec_i8 = __riscv_vand_tu(vIn_vec_i8, vIn_vec_i8, 0, vl);
 97→
 98→            vl = __riscv_vsetvl_e8m4(colCnt2);
 99→            //load src1
100→            vIn_vec_i8 = __riscv_vle8_tu(vIn_vec_i8, in_vec, vl);
101→            //load src2
102→            vWt_mat_i8 = __riscv_vle8_tu(vWt_mat_i8, wt_mat, vl);
103→            vWt_mat2_i8 = __riscv_vle8_tu(vWt_mat2_i8, wt_mat2, vl);
104→            //bump pointers and update loop counter
105→            // colCnt2 -= vl;
106→            // in_vec += vl;
107→            wt_mat += vl;
108→            wt_mat2 += vl;
109→            //set the proper avl/SEW/LMUL values for vd4dot
110→            //remember to deal with the avl of vd4dot is not a multiple of 4 case
111→            vl = (vl + 3) >> 2;
112→            vl = __riscv_vsetvl_e32m4(vl);
113→            //acc += src1 * src2
114→            vAcc0 = __riscv_vd4dots_vv_i32m4_tu(vAcc0, vWt_mat_i8, vIn_vec_i8, vl);
115→            vAcc1 = __riscv_vd4dots_vv_i32m4_tu(vAcc1, vWt_mat2_i8, vIn_vec_i8, vl);
116→        }
117→
118→        vl = __riscv_vsetvl_e32m4(size);    //note the avl here
119→        vint32m1_t vAcc0_sum = __riscv_vredsum(vAcc0, vZero, vl);
120→		vint32m1_t vAcc1_sum = __riscv_vredsum(vAcc1, vZero, vl);
121→
122→        vl = __riscv_vsetvl_e32m1(2);
123→        vAcc0_sum = __riscv_vslideup(vAcc0_sum, vAcc1_sum, 1, vl);
124→
125→        //add bias back
126→        vint32m1_t vBias_i32 = __riscv_vle32_v_i32m1(bias, vl);
127→        vAcc0_sum = __riscv_vadd(vAcc0_sum, vBias_i32, vl);
128→
129→        //scale down, clip and store the results
130→        vAcc0_sum = __riscv_vsra(vAcc0_sum, pre_rshift, vl);
131→        vAcc0_sum = __riscv_vmul(vAcc0_sum, out_scale, vl);
132→        vAcc0_sum = __riscv_vadd(vAcc0_sum, NN_ROUND(post_rshift), vl);
133→        vAcc0_sum = __riscv_vsra(vAcc0_sum, post_rshift, vl);
134→        vl = __riscv_vsetvl_e16mf2(2);
135→        vint16mf2_t vResult_i16 = __riscv_vnclip(vAcc0_sum, 0, __RISCV_VXRM_RNU, vl);
136→        vl = __riscv_vsetvl_e8mf4(2);
137→        vint8mf4_t vResult_i8 = __riscv_vnclip(vResult_i16, 0, __RISCV_VXRM_RNU, vl);
138→        __riscv_vse8(out_vec, vResult_i8, vl);
139→
140→        bias += vl;
141→        wt_mat = wt_mat2;
142→        out_vec += vl;
143→        rowCnt--;
144→    }
145→
146→    if(wt_row_num & 0x1)
147→    {
148→        vl = __riscv_vsetvl_e32m8(size);
149→        vint32m8_t vAcc0 = __riscv_vundefined_i32m8();
150→        //clear acc
151→        vAcc0 = __riscv_vand_tu(vAcc0, vAcc0, 0, vl);    //acc_0
152→        in_vec = in_vec_bak;
153→        long colCnt2 = size;
154→
155→        while(colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
156→        {
157→            vl = __riscv_vsetvl_e8m8(colCnt2);
158→            //load src1
159→            vint8m8_t vIn_vec_i8 = __riscv_vle8_v_i8m8(in_vec, vl);
160→            //load src2
161→            vint8m8_t vWt_mat_i8 = __riscv_vle8_v_i8m8(wt_mat, vl);
162→            //bump pointers and update loop counter
163→            colCnt2 -= vl;
164→            in_vec += vl;
165→            wt_mat += vl;
166→            //set the proper avl/SEW/LMUL values for vd4dot
167→            vl >>= 2;
168→            vl = __riscv_vsetvl_e32m8(vl);
169→            //acc += src1 * src2
170→            vAcc0 = __riscv_vd4dots_vv_i32m8(vAcc0, vWt_mat_i8, vIn_vec_i8, vl);
171→        }
172→
173→        //extra process for the case of vd4dot's avl is not a mutiple of 4
174→        if(colCnt2 > 0)
175→        {
176→            //clean one of the dot product source
177→            vl = __riscv_vsetvlmax_e8m8();
178→            vint8m8_t vIn_vec_i8 = __riscv_vundefined_i8m8();
179→            vint8m8_t vWt_mat_i8 = __riscv_vundefined_i8m8();
180→            vIn_vec_i8 = __riscv_vand_tu(vIn_vec_i8, vIn_vec_i8, 0, vl);
181→
182→            vl = __riscv_vsetvl_e8m8(colCnt2);
183→            //load src1
184→            vIn_vec_i8 = __riscv_vle8_tu(vIn_vec_i8, in_vec, vl);
185→            //load src2
186→            vWt_mat_i8 = __riscv_vle8_tu(vWt_mat_i8, wt_mat, vl);
187→            //set the proper avl/SEW/LMUL values for vd4dot
188→            //remember to deal with the avl of vd4dot is not a multiple of 4 case
189→            vl = (vl + 3) >> 2;
190→            vl = __riscv_vsetvl_e32m8(vl);
191→            //acc += src1 * src2
192→            vAcc0 = __riscv_vd4dots_vv_i32m8_tu(vAcc0, vWt_mat_i8, vIn_vec_i8, vl);
193→        }
194→
195→        vl = __riscv_vsetvl_e32m8(size);    //note the avl here
196→        vint32m1_t vAcc0_sum = __riscv_vredsum(vAcc0, vZero, vl);
197→
198→        //add bias back
199→        vl = __riscv_vsetvl_e32m1(1);
200→        vint32m1_t vBias_i32 = __riscv_vle32_v_i32m1(bias, vl);

