 23→
 24→//// Convolution Functions
 25→
 26→q7_t *nn_mat_mult_kernel_s8_offset(const q7_t *input_a,
 27→                                   const q7_t *input_b,
 28→                                   const uint16_t output_ch,
 29→                                   const int32_t *out_shift,
 30→                                   const int32_t *out_mult,
 31→                                   const int32_t input_offset,     //value is in the range of [-127, 128]
 32→                                   const int32_t out_offset,       //value is in the range of [-128, 127]
 33→                                   const int16_t activation_min,
 34→                                   const int16_t activation_max,
 35→                                   const uint16_t num_col_a,
 36→                                   const int32_t *const output_bias,
 37→                                   q7_t *out_0)
 38→{
 39→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
 40→    /* set up the second output pointers */
 41→    q7_t *out_1 = out_0 + output_ch;
 42→    const int32_t *bias = output_bias;
 43→
 44→    long row_count = output_ch >> 1;
 45→    const q7_t *ptr_a0 = input_a;
 46→
 47→    long vl;
 48→    long vlenb = NDS_VEC_CSR_GET_VLENB();
 49→
 50→    vint32m1_t vZero_e0 = __riscv_vand(__riscv_vundefined_i32m1(), 0, 1);    //const zero for redsum
 51→
 52→    /* this loop over rows in A */
 53→    while (row_count)
 54→    {
 55→        vl = __riscv_vsetvl_e8m2(num_col_a);
 56→        vint8m2_t vOne_i8m2 = __riscv_vmv_v_x_i8m2(1, vl);                   //const one
 57→
 58→        /* setup pointers for B */
 59→        const q7_t *ptr_b0 = input_b;
 60→        const q7_t *ptr_b1 = ptr_b0 + num_col_a;
 61→
 62→        /* align the second pointer for A */
 63→        const q7_t *ptr_a1 = ptr_a0 + num_col_a;
 64→
 65→        long col_count = num_col_a;
 66→
 67→        // init the accumulator
 68→        vl = __riscv_vsetvl_e32m2(num_col_a);
 69→        vint32m2_t vAcc0 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
 70→        vint32m2_t vAcc1 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
 71→        vint32m2_t vAcc2 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
 72→        vint32m2_t vAcc3 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
 73→        vint32m2_t vAcc_wt_0 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
 74→        vint32m2_t vAcc_wt_1 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
 75→
 76→        while(col_count >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M2))
 77→        {
 78→            vl = __riscv_vsetvl_e8m2(col_count);
 79→            vint8m2_t vA0_i8m2 = __riscv_vle8_v_i8m2(ptr_a0, vl);
 80→            vint8m2_t vA1_i8m2 = __riscv_vle8_v_i8m2(ptr_a1, vl);
 81→            vint8m2_t vB0_i8m2 = __riscv_vle8_v_i8m2(ptr_b0, vl);
 82→            vint8m2_t vB1_i8m2 = __riscv_vle8_v_i8m2(ptr_b1, vl);
 83→            ptr_a0 += vl;
 84→            ptr_a1 += vl;
 85→            ptr_b0 += vl;
 86→            ptr_b1 += vl;
 87→            col_count -= vl;
 88→
 89→            vl = __riscv_vsetvl_e32m2(vl);
 90→            vAcc0 = __riscv_vd4dots_vv_i32m2_tu(vAcc0, vA0_i8m2, vB0_i8m2, vl);     //ch_0_out_0 += a0 * b0;
 91→            vAcc1 = __riscv_vd4dots_vv_i32m2_tu(vAcc1, vA0_i8m2, vB1_i8m2, vl);     //ch_0_out_1 += a0 * b1;
 92→            vAcc2 = __riscv_vd4dots_vv_i32m2_tu(vAcc2, vA1_i8m2, vB0_i8m2, vl);     //ch_1_out_0 += a1 * b0;
 93→            vAcc3 = __riscv_vd4dots_vv_i32m2_tu(vAcc3, vA1_i8m2, vB1_i8m2, vl);     //ch_1_out_1 += a1 * b1;
 94→            vAcc_wt_0 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_0, vA0_i8m2, vOne_i8m2, vl);    //sum_input_a0 += a0;
 95→            vAcc_wt_1 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_1, vA1_i8m2, vOne_i8m2, vl);    //sum_input_a1 += a1;
 96→        }
 97→
 98→        //extra process for the case of elements to be dot producted is not a mutiple of 4
 99→        if(col_count > 0)
100→        {
101→            //clean one of the dot product source
102→            vl = __riscv_vsetvl_e8m2(col_count+3);
103→            vint8m2_t vA0_i8m2 = __riscv_vand(__riscv_vundefined_i8m2(), 0, vl);
104→            vint8m2_t vA1_i8m2 = __riscv_vand(__riscv_vundefined_i8m2(), 0, vl);
105→            vint8m2_t vB0_i8m2, vB1_i8m2;
106→
107→            vl = __riscv_vsetvl_e8m2(col_count);
108→            vA0_i8m2 = __riscv_vle8_v_i8m2_tu(vA0_i8m2, ptr_a0, vl);
109→            vA1_i8m2 = __riscv_vle8_v_i8m2_tu(vA1_i8m2, ptr_a1, vl);
110→            vB0_i8m2 = __riscv_vle8_v_i8m2(ptr_b0, vl);
111→            vB1_i8m2 = __riscv_vle8_v_i8m2(ptr_b1, vl);
112→            ptr_a0 += vl;
113→            ptr_a1 += vl;
114→            ptr_b0 += vl;
115→            ptr_b1 += vl;
116→            col_count -= vl;
117→
118→            vl = (vl + 3) >> 2;
119→            vl = __riscv_vsetvl_e32m2(vl);
120→            vAcc0 = __riscv_vd4dots_vv_i32m2_tu(vAcc0, vA0_i8m2, vB0_i8m2, vl);     //ch_0_out_0 += a0 * b0;
121→            vAcc1 = __riscv_vd4dots_vv_i32m2_tu(vAcc1, vA0_i8m2, vB1_i8m2, vl);     //ch_0_out_1 += a0 * b1;
122→            vAcc2 = __riscv_vd4dots_vv_i32m2_tu(vAcc2, vA1_i8m2, vB0_i8m2, vl);     //ch_1_out_0 += a1 * b0;
123→            vAcc3 = __riscv_vd4dots_vv_i32m2_tu(vAcc3, vA1_i8m2, vB1_i8m2, vl);     //ch_1_out_1 += a1 * b1;
124→            vAcc_wt_0 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_0, vA0_i8m2, vOne_i8m2, vl);    //sum_input_a0 += a0;
125→            vAcc_wt_1 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_1, vA1_i8m2, vOne_i8m2, vl);    //sum_input_a1 += a1;
126→        }
127→
128→        vl = __riscv_vsetvl_e32m2(num_col_a);
129→        vint32m1_t vSum_e0_0 = __riscv_vundefined_i32m1();
130→        vint32m1_t vSum_e0_1 = __riscv_vundefined_i32m1();
131→        vint32m1_t vSum_e0_2 = __riscv_vundefined_i32m1();
132→        vint32m1_t vSum_e0_3 = __riscv_vundefined_i32m1();
133→        vint32m1_t vSum_wt_e0_0 = __riscv_vundefined_i32m1();
134→        vint32m1_t vSum_wt_e0_1 = __riscv_vundefined_i32m1();
135→        vSum_e0_0 = __riscv_vredsum_tu(vSum_e0_0, vAcc0, vZero_e0, vl);
136→        vSum_e0_1 = __riscv_vredsum_tu(vSum_e0_1, vAcc1, vZero_e0, vl);
137→        vSum_e0_2 = __riscv_vredsum_tu(vSum_e0_2, vAcc2, vZero_e0, vl);
138→        vSum_e0_3 = __riscv_vredsum_tu(vSum_e0_3, vAcc3, vZero_e0, vl);
139→        vSum_wt_e0_0 = __riscv_vredsum_tu(vSum_wt_e0_0, vAcc_wt_0, vZero_e0, vl);
140→        vSum_wt_e0_1 = __riscv_vredsum_tu(vSum_wt_e0_1, vAcc_wt_1, vZero_e0, vl);
141→
142→        vl = __riscv_vsetvl_e32m1(2);
143→        vSum_e0_0 = __riscv_vslideup(vSum_e0_0, vSum_e0_2, 1, vl);
144→        vSum_e0_1 = __riscv_vslideup(vSum_e0_1, vSum_e0_3, 1, vl);
145→        vSum_wt_e0_0 = __riscv_vslideup(vSum_wt_e0_0, vSum_wt_e0_1, 1, vl);
146→
147→        //add input_offset back
148→        vSum_e0_0 = __riscv_vmacc(vSum_e0_0, input_offset, vSum_wt_e0_0, vl);
149→        vSum_e0_1 = __riscv_vmacc(vSum_e0_1, input_offset, vSum_wt_e0_0, vl);
150→
151→        //add bias back
152→        if (bias)
153→        {
154→            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
155→            bias += vl;
156→            vSum_e0_0 = __riscv_vadd(vSum_e0_0, vBias, vl);
157→            vSum_e0_1 = __riscv_vadd(vSum_e0_1, vBias, vl);
158→        }
159→
160→        //===== Quantize down =====
161→        vuint32m1_t vShf = __riscv_vle32_v_u32m1((u32_t*)out_shift, vl);
162→        vint32m1_t vMul = __riscv_vle32_v_i32m1(out_mult, vl);
163→        vShf = __riscv_vrsub(vShf, 30, vl);
164→
165→        vint64m2_t vSum_i64_0 = __riscv_vwmul(vSum_e0_0, vMul, vl);
166→        vint64m2_t vSum_i64_1 = __riscv_vwmul(vSum_e0_1, vMul, vl);
167→        vSum_e0_0 = __riscv_vnsra(vSum_i64_0, vShf, vl);
168→        vSum_e0_1 = __riscv_vnsra(vSum_i64_1, vShf, vl);
169→        vSum_e0_0 = __riscv_vssra(vSum_e0_0, 1, __RISCV_VXRM_RNU, vl);
170→        vSum_e0_1 = __riscv_vssra(vSum_e0_1, 1, __RISCV_VXRM_RNU, vl);
171→
172→        // Add offset
173→        vSum_e0_0 = __riscv_vadd(vSum_e0_0, out_offset, vl);
174→        vSum_e0_1 = __riscv_vadd(vSum_e0_1, out_offset, vl);
175→
176→        // Clamp the result
177→        vSum_e0_0 = __riscv_vmax(vSum_e0_0, activation_min, vl);
178→        vSum_e0_0 = __riscv_vmin(vSum_e0_0, activation_max, vl);
179→        vSum_e0_1 = __riscv_vmax(vSum_e0_1, activation_min, vl);
180→        vSum_e0_1 = __riscv_vmin(vSum_e0_1, activation_max, vl);
181→
182→        //narrowing and store the results
183→        vint16mf2_t vSum_i16_0 = __riscv_vnsra(vSum_e0_0, 0, vl);
184→        vint16mf2_t vSum_i16_1 = __riscv_vnsra(vSum_e0_1, 0, vl);
185→        vint8mf4_t vSum_i8_0 = __riscv_vnsra(vSum_i16_0, 0, vl);
186→        vint8mf4_t vSum_i8_1 = __riscv_vnsra(vSum_i16_1, 0, vl);
187→        __riscv_vse8(out_0, vSum_i8_0, vl);
188→        __riscv_vse8(out_1, vSum_i8_1, vl);
189→        out_0 += vl;
190→        out_1 += vl;
191→        out_mult += vl;
192→        out_shift += vl;
193→
194→        /* skip row */
195→        ptr_a0 += num_col_a;
196→        row_count--;
197→    }
198→
199→    /* compute the last odd numbered row if any */
200→    if (output_ch & 0x1)
201→    {
202→        vl = __riscv_vsetvl_e8m4(num_col_a);
203→        vint8m4_t vOne_i8m4 = __riscv_vmv_v_x_i8m4(1, vl);                   //const one
204→
205→        /* setup pointers for B */
206→        const q7_t *ptr_b0 = input_b;
207→        const q7_t *ptr_b1 = ptr_b0 + num_col_a;
208→
209→        q31_t sum_input_a0 = 0;
210→        long col_count = num_col_a;
211→
212→        // init the accumulator
213→        vl = __riscv_vsetvl_e32m4(num_col_a);
214→        vint32m4_t vAcc0 = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);
215→        vint32m4_t vAcc1 = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);
216→        vint32m4_t vAcc_wt = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);
217→
218→        while(col_count >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M4))
219→        {
220→            vl = __riscv_vsetvl_e8m4(col_count);
221→            vint8m4_t vA0_i8m4 = __riscv_vle8_v_i8m4(ptr_a0, vl);
222→            vint8m4_t vB0_i8m4 = __riscv_vle8_v_i8m4(ptr_b0, vl);
223→            vint8m4_t vB1_i8m4 = __riscv_vle8_v_i8m4(ptr_b1, vl);
224→            col_count -= vl;
225→            ptr_a0 += vl;
226→            ptr_b0 += vl;
227→            ptr_b1 += vl;
228→
229→            vl = __riscv_vsetvl_e32m4(vl);
230→            vAcc0 = __riscv_vd4dots_vv_i32m4_tu(vAcc0, vA0_i8m4, vB0_i8m4, vl);
231→            vAcc1 = __riscv_vd4dots_vv_i32m4_tu(vAcc1, vA0_i8m4, vB1_i8m4, vl);
232→            vAcc_wt = __riscv_vd4dots_vv_i32m4_tu(vAcc_wt, vA0_i8m4, vOne_i8m4, vl);
233→        }
234→
235→        if(col_count > 0)
236→        {
237→            //clean one of the dot product source
238→            vl = __riscv_vsetvl_e8m4(col_count+3);
239→            vint8m4_t vA0_i8m4 = __riscv_vand(__riscv_vundefined_i8m4(), 0, vl);
240→            vint8m4_t vB0_i8m4, vB1_i8m4;
241→
242→            vl = __riscv_vsetvl_e8m4(col_count);
243→            vA0_i8m4 = __riscv_vle8_v_i8m4_tu(vA0_i8m4, ptr_a0, vl);
244→            vB0_i8m4 = __riscv_vle8_v_i8m4(ptr_b0, vl);
245→            vB1_i8m4 = __riscv_vle8_v_i8m4(ptr_b1, vl);
246→            col_count -= vl;
247→            ptr_a0 += vl;
248→            ptr_b0 += vl;
249→            ptr_b1 += vl;
250→
251→            vl = (vl + 3) >> 2;
252→            vl = __riscv_vsetvl_e32m4(vl);
253→            vAcc0 = __riscv_vd4dots_vv_i32m4_tu(vAcc0, vA0_i8m4, vB0_i8m4, vl);
254→            vAcc1 = __riscv_vd4dots_vv_i32m4_tu(vAcc1, vA0_i8m4, vB1_i8m4, vl);
255→            vAcc_wt = __riscv_vd4dots_vv_i32m4_tu(vAcc_wt, vA0_i8m4, vOne_i8m4, vl);
256→        }
257→
258→        vl = __riscv_vsetvl_e32m4(num_col_a);       //note the avl here
259→        vint32m1_t vSum_e0_0 = __riscv_vundefined_i32m1();
260→        vint32m1_t vSum_e0_1 = __riscv_vundefined_i32m1();
261→        vint32m1_t vSum_wt_e0 = __riscv_vundefined_i32m1();
262→        vSum_e0_0 = __riscv_vredsum_tu(vSum_e0_0, vAcc0, vZero_e0, vl);
263→        vSum_e0_1 = __riscv_vredsum_tu(vSum_e0_1, vAcc1, vZero_e0, vl);
264→        vSum_wt_e0 = __riscv_vredsum_tu(vSum_wt_e0, vAcc_wt, vZero_e0, vl);
265→
266→        sum_input_a0 = __riscv_vmv_x(vSum_wt_e0);
267→        sum_input_a0 *= input_offset;
268→
269→        vl = __riscv_vsetvl_e32m1(2);
270→        vSum_e0_0 = __riscv_vslideup(vSum_e0_0, vSum_e0_1, 1, vl);
271→
272→        //add input_offset back
273→        vSum_e0_0 = __riscv_vadd(vSum_e0_0, sum_input_a0, vl);
274→
275→        //add bias back
276→        if (bias)
277→        {
278→            long bias_val = *bias++;
279→            vSum_e0_0 = __riscv_vadd(vSum_e0_0, bias_val, vl);
280→        }
281→
282→        //===== Quantize down =====
283→        long out_mult_val = *out_mult,
284→             out_shift_val = 30 - *out_shift;
285→
286→        vint64m2_t vSum_i64 = __riscv_vwmul(vSum_e0_0, out_mult_val, vl);
287→        vSum_e0_0 = __riscv_vnsra(vSum_i64, out_shift_val, vl);
288→        vSum_e0_0 = __riscv_vssra(vSum_e0_0, 1, __RISCV_VXRM_RNU, vl);
289→
290→        // Add offset
291→        vSum_e0_0 = __riscv_vadd(vSum_e0_0, out_offset, vl);
292→
293→        // Clamp the result
294→        vSum_e0_0 = __riscv_vmax(vSum_e0_0, activation_min, vl);
295→        vSum_e0_0 = __riscv_vmin(vSum_e0_0, activation_max, vl);
296→
297→        //narrowing and store the results
298→        vint16mf2_t vSum_i16 = __riscv_vnsra(vSum_e0_0, 0, vl);
299→        vint8mf4_t vSum_i8 = __riscv_vnsra(vSum_i16, 0, vl);
300→        __riscv_vsse8(out_0, output_ch, vSum_i8, vl);
301→        out_0++;
302→        out_mult++;
303→        out_shift++;
304→    }
305→
306→    out_0 += output_ch;
307→
308→    /* return the new output pointer with offset */
309→    return out_0;
310→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
311→    /* set up the second output pointers */
312→    q7_t *out_1 = out_0 + output_ch;
313→    const int32_t *bias = output_bias;
314→
315→    long row_count = output_ch >> 1;
316→    const q7_t *ptr_a0 = input_a;
317→
318→    long vl;
319→    long vlenb = NDS_VEC_CSR_GET_VLENB();
320→
321→#if (__clang__)
322→    register const long zero asm ("x0") = 0;
323→#else
324→    register const long zero asm ("x0");
325→#endif
326→
327→    NDS_VEC_VSETVLI(vl, zero, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
328→    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);     // const zero for redsum
329→    NDS_VEC_VSETVLI(vl, zero, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
330→    NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);     // const one for vd4dot
331→    NDS_VEC_VADD_VI(NDS_VEC_V24, NDS_VEC_V24, 1);     // const one for vd4dot
332→
333→    /* this loop over rows in A */
334→    while (row_count)
335→    {
336→        /* setup pointers for B */
337→        const q7_t *ptr_b0 = input_b;
338→        const q7_t *ptr_b1 = ptr_b0 + num_col_a;
339→
340→        /* align the second pointer for A */
341→        const q7_t *ptr_a1 = ptr_a0 + num_col_a;
342→
343→        long col_count = num_col_a;
344→
345→        //init
346→        //clear v0~v11 (keep multiplication results)
347→        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
348→        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
349→        NDS_VEC_VAND_VI(NDS_VEC_V2, NDS_VEC_V2, 0x0);
350→        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
351→        NDS_VEC_VAND_VI(NDS_VEC_V6, NDS_VEC_V6, 0x0);
352→        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
353→        NDS_VEC_VAND_VI(NDS_VEC_V10, NDS_VEC_V10, 0x0);
354→
355→        while(col_count >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M2))
356→        {
357→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
358→            NDS_VEC_VLB_V(NDS_VEC_V12, ptr_a0);
359→            NDS_VEC_VLB_V(NDS_VEC_V14, ptr_b0);
360→            NDS_VEC_VLB_V(NDS_VEC_V16, ptr_b1);
361→            NDS_VEC_VLB_V(NDS_VEC_V18, ptr_a1);
362→            ptr_a0 += vl;
363→            ptr_a1 += vl;
364→            ptr_b0 += vl;
365→            ptr_b1 += vl;
366→            col_count -= vl;
367→
368→            vl >>= 2;
369→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
370→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V12, NDS_VEC_V14);   //ch_0_out_0 += a0 * b0;
371→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V2, NDS_VEC_V12, NDS_VEC_V16);   //ch_0_out_1 += a0 * b1;
372→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V12, NDS_VEC_V24);   //sum_input_a0 += a0;
373→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V18, NDS_VEC_V14);   //ch_1_out_0 += a1 * b0;
374→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V6, NDS_VEC_V18, NDS_VEC_V16);   //ch_1_out_1 += a1 * b1;
375→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V24);  //sum_input_a1 += a1;
376→        }
377→
378→        //extra process for the case of elements to be dot producted is not a mutiple of 4
379→        if(col_count > 0)
380→        {
381→            //clean one of the dot product source
382→            NDS_VEC_VSETVLI(vl, zero, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
383→            NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0);
384→            NDS_VEC_VAND_VI(NDS_VEC_V18, NDS_VEC_V18, 0);
385→
386→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
387→            NDS_VEC_VLB_V(NDS_VEC_V12, ptr_a0);
388→            NDS_VEC_VLB_V(NDS_VEC_V14, ptr_b0);
389→            NDS_VEC_VLB_V(NDS_VEC_V16, ptr_b1);
390→            NDS_VEC_VLB_V(NDS_VEC_V18, ptr_a1);
391→            ptr_a0 += vl;
392→            ptr_a1 += vl;
393→            ptr_b0 += vl;
394→            ptr_b1 += vl;
395→            col_count -= vl;
396→
397→            vl = (vl + 3) >> 2;
398→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
399→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V12, NDS_VEC_V14);   //ch_0_out_0 += a0 * b0;
400→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V2, NDS_VEC_V12, NDS_VEC_V16);   //ch_0_out_1 += a0 * b1;

