 26→//// Convolution Functions
 27→
 28→int32_t riscv_nn_conv_trans_HWC_s8_s8_s8_asym_bias_any(const int8_t * in_tensor,
 29→                                                       const uint16_t in_tensor_dim_x,
 30→                                                       const uint16_t in_tensor_dim_y,
 31→                                                       const uint16_t in_tensor_ch,
 32→                                                       const uint16_t in_tensor_batch,
 33→                                                       const int8_t * ker_weight,
 34→                                                       const uint16_t out_tensor_ch,
 35→                                                       const uint16_t ker_dim_x,
 36→                                                       const uint16_t ker_dim_y,
 37→                                                       const uint16_t pad_x,
 38→                                                       const uint16_t pad_y,
 39→                                                       const uint16_t pad_offset_x,
 40→                                                       const uint16_t pad_offset_y,
 41→                                                       const uint16_t stride_x,
 42→                                                       const uint16_t stride_y,
 43→                                                       const int32_t * bias,
 44→                                                       int8_t * out_tensor,
 45→                                                       const int32_t * out_shift,
 46→                                                       const int32_t * out_scale,
 47→                                                       const int32_t out_offset,
 48→                                                       const int32_t in_offset,
 49→                                                       const int32_t act_min,
 50→                                                       const int32_t act_max,
 51→                                                       const uint16_t out_tensor_dim_x,
 52→                                                       const uint16_t out_tensor_dim_y,
 53→                                                       int8_t * tmp_buf)
 54→{
 55→#ifdef ENA_EMPTY_FUN
 56→    //empty body
 57→#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_ISA_ZVQMAC) && defined(ENA_NDS_V5_VEC_DOT_PROD) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ELEN64)
 58→#if defined(ENA_VEC_INTRINSIC)
 59→    (void)pad_offset_x;
 60→    (void)pad_offset_y;
 61→
 62→    int8_t *wt_tmp_buf = NULL;  //(data layout: (Cin,H,W,Cout))
 63→    //temporary buffer for the weight offset contributionbution for each input channel (data layout: (H,W,Cout))
 64→    int32_t *wt_contribution_buf = NULL;
 65→
 66→    const uint32_t align_byte = 64;
 67→    uint32_t tmp_buf_offset = (out_tensor_ch * out_tensor_dim_y * out_tensor_dim_x) * sizeof(int32_t);
 68→    tmp_buf_offset = nn_align(tmp_buf_offset, align_byte);
 69→    wt_tmp_buf = &tmp_buf[tmp_buf_offset];
 70→    tmp_buf_offset += out_tensor_ch * ker_dim_y * ker_dim_x * in_tensor_ch;
 71→    tmp_buf_offset = nn_align(tmp_buf_offset, align_byte);
 72→    wt_contribution_buf = (int32_t*)&tmp_buf[tmp_buf_offset];
 73→
 74→    const int8_t *pWt1 = ker_weight;
 75→    const long stride_len  = ker_dim_y * ker_dim_x * out_tensor_ch;
 76→    const long stride_byte = ker_dim_y * ker_dim_x * out_tensor_ch * sizeof(*ker_weight);
 77→    long vl;
 78→    vl = __riscv_vsetvl_e32m1(1);
 79→    vint32m1_t vZero = __riscv_vundefined_i32m1();
 80→    vZero = __riscv_vand(vZero, 0, 1);     //const zero for redsum
 81→    long max_vl_per_vg = __riscv_vsetvlmax_e8m8();
 82→    const int cst_one_s8x4 = 0x01;
 83→    vint8m8_t v_cst_one_s8x4 = __riscv_vmv_v_x_i8m8(cst_one_s8x4, max_vl_per_vg);
 84→    for (long i_out_ch = 0; i_out_ch < out_tensor_ch; i_out_ch++)
 85→    {
 86→        for (long i_ker_y = 0; i_ker_y < ker_dim_y; i_ker_y++)
 87→        {
 88→            for (long i_ker_x = 0; i_ker_x < ker_dim_x; i_ker_x++)
 89→            {
 90→                int8_t *pWt2 = &wt_tmp_buf[(i_ker_y * ker_dim_x + i_ker_x) * out_tensor_ch + i_out_ch];
 91→                long rest_in_ch = in_tensor_ch;
 92→
 93→                vl = __riscv_vsetvl_e32m8(rest_in_ch);
 94→                vint32m8_t vAcc = __riscv_vmv_v_x_i32m8(0, vl);
 95→
 96→                vint8m8_t vWt1_i8m8 = __riscv_vundefined_i8m8();
 97→                while (rest_in_ch >= max_vl_per_vg)
 98→                {
 99→
100→                    vl = __riscv_vsetvl_e8m8(rest_in_ch);
101→                    vWt1_i8m8 = __riscv_vle8_v_i8m8_tu(vWt1_i8m8, pWt1, vl);
102→                    __riscv_vsse8(pWt2, stride_byte, vWt1_i8m8, vl);
103→                    pWt1 += vl;
104→                    pWt2 += stride_len * vl;
105→                    rest_in_ch -= vl;
106→
107→                    vl >>= 2;
108→                    vl = __riscv_vsetvl_e32m8(vl);
109→                    vAcc  = __riscv_vd4dots_vv_i32m8_tu(vAcc, vWt1_i8m8, v_cst_one_s8x4, vl);
110→                }
111→
112→                while (rest_in_ch > 0)
113→                {
114→                    //clean one of the dot product source
115→                    vl = __riscv_vsetvlmax_e8m8();
116→                    vWt1_i8m8 = __riscv_vmv_v_x_i8m8_tu(vWt1_i8m8, 0, vl);
117→
118→                    vl = __riscv_vsetvl_e8m8(rest_in_ch);
119→                    vWt1_i8m8 = __riscv_vle8_v_i8m8_tu(vWt1_i8m8, pWt1, vl);
120→                    __riscv_vsse8(pWt2, stride_byte, vWt1_i8m8, vl);
121→                    pWt1 += vl;
122→                    pWt2 += stride_len * vl;
123→                    rest_in_ch -= vl;
124→
125→                    vl = (vl + 3) >> 2;
126→                    vl = __riscv_vsetvl_e32m8(vl);
127→                    vAcc  = __riscv_vd4dots_vv_i32m8_tu(vAcc, vWt1_i8m8, v_cst_one_s8x4, vl);
128→                }
129→                vl = __riscv_vsetvl_e32m8(in_tensor_ch);
130→                vint32m1_t vSum = __riscv_vredsum_vs_i32m8_i32m1(vAcc, vZero, vl);
131→
132→                int32_t *pWt_contri = &wt_contribution_buf[(i_ker_y * ker_dim_x + i_ker_x) * out_tensor_ch + i_out_ch];
133→                vl = __riscv_vsetvl_e32m1(1);
134→                __riscv_vse32(pWt_contri, vSum, vl);
135→            }
136→        }
137→    }
138→
139→    int32_t *out_tmp_buf = (int32_t*)tmp_buf;
140→    for (long i_batch = 0; i_batch < in_tensor_batch; i_batch++)
141→    {
142→        nn_set_zero_s8((int8_t*)out_tmp_buf, sizeof(int32_t) * out_tensor_dim_y * out_tensor_dim_x * out_tensor_ch);
143→
144→        for (long i_in_y = 0; i_in_y < in_tensor_dim_y; i_in_y++)
145→        {
146→            for (long i_in_x = 0; i_in_x < in_tensor_dim_x; i_in_x++)
147→            {
148→                const long out_x_origin = (i_in_x * stride_x) - pad_x;
149→                const long out_y_origin = (i_in_y * stride_y) - pad_y;
150→                for (long i_ker_y = 0; i_ker_y < ker_dim_y; i_ker_y++)
151→                {
152→                    long i_ker_x = 0;
153→                    for (; (i_ker_x + 3 <= ker_dim_x) && (out_x_origin + i_ker_x >= 0) && (out_x_origin + i_ker_x + 3 <= out_tensor_dim_x); i_ker_x += 3)
154→                    {
155→                        const long i_out_x = out_x_origin + i_ker_x;
156→                        const long i_out_y = out_y_origin + i_ker_y;
157→
158→                        if ((i_out_x >= 0) &&
159→                            (i_out_x + 3 <= out_tensor_dim_x) &&
160→                            (i_out_y >= 0) &&
161→                            (i_out_y < out_tensor_dim_y))
162→                        {
163→                            long rest_out_ch = out_tensor_ch;
164→                            while (rest_out_ch > 0)
165→                            {
166→                                long vl;
167→                                int8_t *pWt1 = &wt_tmp_buf[(i_ker_y * ker_dim_x + i_ker_x ) * out_tensor_ch + (out_tensor_ch - rest_out_ch)];
168→                                int8_t *pWt2 = pWt1 + out_tensor_ch;
169→                                int8_t *pWt3 = pWt2 + out_tensor_ch;
170→                                int32_t *pWt_contri_1 = &wt_contribution_buf[(i_ker_y * ker_dim_x + i_ker_x) * out_tensor_ch + (out_tensor_ch - rest_out_ch)];
171→                                int32_t *pWt_contri_2 = pWt_contri_1 + out_tensor_ch;
172→                                int32_t *pWt_contri_3 = pWt_contri_2 + out_tensor_ch;
173→                                int32_t *pOut1 = &out_tmp_buf[(i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch + (out_tensor_ch - rest_out_ch)];
174→                                int32_t *pOut2 = pOut1 + out_tensor_ch;
175→                                int32_t *pOut3 = pOut2 + out_tensor_ch;
176→                                // load the partial results
177→                                vl = __riscv_vsetvl_e32m8(rest_out_ch);
178→                                vint32m8_t vAcc0 = __riscv_vundefined_i32m8();
179→                                vAcc0 =__riscv_vle32_v_i32m8_tu(vAcc0, pOut1, vl);
180→                                vint32m8_t vAcc1 = __riscv_vundefined_i32m8();
181→                                vAcc1 = __riscv_vle32_v_i32m8_tu(vAcc1, pOut2, vl);
182→                                vint32m8_t vAcc2 = __riscv_vundefined_i32m8();
183→                                vAcc2 = __riscv_vle32_v_i32m8_tu(vAcc2, pOut3, vl);
184→                                vl = __riscv_vsetvl_e8m2(vl);
185→                                rest_out_ch -= vl;
186→                                const int8_t *pIn = &in_tensor[(i_in_y * in_tensor_dim_x + i_in_x) * in_tensor_ch];
187→                                for (long i_in_ch = 0; i_in_ch < in_tensor_ch; i_in_ch++)
188→                                {
189→                                    long in_val = *pIn++;
190→                                    vint8m2_t vWt1 = __riscv_vundefined_i8m2();
191→                                    vWt1 = __riscv_vle8_v_i8m2_tu(vWt1, pWt1, vl);
192→                                    pWt1 += ker_dim_y * ker_dim_x * out_tensor_ch;
193→                                    vint8m2_t vWt2 = __riscv_vundefined_i8m2();
194→                                    vWt2 = __riscv_vle8_v_i8m2_tu(vWt2, pWt2, vl);
195→                                    pWt2 += ker_dim_y * ker_dim_x * out_tensor_ch;
196→                                    vint8m2_t vWt3 = __riscv_vundefined_i8m2();
197→                                    vWt3 =__riscv_vle8_v_i8m2_tu(vWt3, pWt3, vl);
198→                                    pWt3 += ker_dim_y * ker_dim_x * out_tensor_ch;
199→                                    vAcc0 = __riscv_vqmacc(vAcc0, in_val, vWt1, vl);
200→                                    vAcc1 = __riscv_vqmacc(vAcc1, in_val, vWt2, vl);

