 31→int32_t riscv_nn_conv_dw_HWC_3x3_s8_s8_s8_asym_bias_any(const int8_t * in_tensor,
 32→                                                        const int32_t in_tensor_dim_x,
 33→                                                        const int32_t in_tensor_dim_y,
 34→                                                        const int32_t in_tensor_ch,
 35→                                                        const int8_t * ker_weight,
 36→                                                        const int32_t out_tensor_ch,
 37→                                                        const int32_t pad_x,
 38→                                                        const int32_t pad_y,
 39→                                                        const int32_t stride_x,
 40→                                                        const int32_t stride_y,
 41→                                                        const int32_t * bias,
 42→                                                        int8_t * out_tensor,
 43→                                                        const int32_t * out_shift,
 44→                                                        const int32_t * out_scale,
 45→                                                        const int32_t out_tensor_dim_x,
 46→                                                        const int32_t out_tensor_dim_y,
 47→                                                        const int32_t out_offset,  //value is in the range of [-127, 128]
 48→                                                        const int32_t in_offset,   //value is in the range of [-128, 127]
 49→                                                        const int32_t act_min,
 50→                                                        const int32_t act_max,
 51→                                                        const int32_t dilation_x,
 52→                                                        const int32_t dilation_y,
 53→                                                        int16_t * tmp_buf)
 54→{
 55→#ifdef ENA_EMPTY_FUN
 56→    //empty body
 57→#else
 58→    // Check input constraints
 59→    if((in_tensor_ch != out_tensor_ch) || (pad_x > 1))
 60→    {
 61→        return -1;
 62→    }
 63→
 64→    (void)dilation_x;
 65→    (void)dilation_y;
 66→    (void)tmp_buf;
 67→
 68→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 69→    long vl;
 70→
 71→    for(long in_y = -pad_y, out_y = 0; out_y < out_tensor_dim_y; in_y += stride_y, out_y++)
 72→    {
 73→        long ker_y_start = MAX(0, -in_y);
 74→        for(long in_x = -pad_x, out_x = 0; out_x < out_tensor_dim_x; in_x += stride_x, out_x++)
 75→        {
 76→            long cur_ch = 0;
 77→            long ker_x_start = MAX(0, -in_x);
 78→
 79→            long rest_in_ch = in_tensor_ch;
 80→            for(; cur_ch < in_tensor_ch; cur_ch += vl)
 81→            {
 82→                int32_t *bias_ptr = (int32_t *)&bias[cur_ch];
 83→                int32_t *out_shift_ptr = (int32_t *)&out_shift[cur_ch];
 84→                int32_t *out_scale_ptr = (int32_t *)&out_scale[cur_ch];
 85→
 86→                vint32m4_t acc_i32;
 87→                vint8m1_t  in_val_i8, wt_val_i8;
 88→                vint16m2_t in_val_i16, wt_val_i16;
 89→
 90→                vl = __riscv_vsetvl_e32m4(rest_in_ch);
 91→                if(bias != NULL)
 92→                {
 93→                    acc_i32 = __riscv_vle32_v_i32m4(bias_ptr, vl);
 94→                }
 95→                else
 96→                {
 97→                    acc_i32 = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);
 98→                }
 99→
100→                const int8_t *input_ptr  = in_tensor + (in_y + ker_y_start) * (in_tensor_ch * in_tensor_dim_x) + in_x * in_tensor_ch + cur_ch;
101→                const int8_t *kernel_ptr = ker_weight + ker_y_start * (in_tensor_ch * 3) + cur_ch;
102→
103→                for(long ker_y = ker_y_start; ker_y < MIN(3, in_tensor_dim_y - in_y); ++ker_y)
104→                {
105→                    if(ker_x_start == 0)
106→                    {
107→                        in_val_i8 = __riscv_vle8_v_i8m1(input_ptr, vl);
108→                        wt_val_i8 = __riscv_vle8_v_i8m1(kernel_ptr, vl);
109→                        in_val_i16 = __riscv_vsext_vf2(in_val_i8, vl);
110→                        wt_val_i16 = __riscv_vsext_vf2(wt_val_i8, vl);
111→                        in_val_i16 = __riscv_vadd(in_val_i16, in_offset, vl);
112→                        acc_i32 = __riscv_vwmacc(acc_i32, in_val_i16, wt_val_i16, vl);
113→                    }
114→
115→                    int8_t *input_ptr2 = (int8_t *)(input_ptr + in_tensor_ch);
116→                    int8_t *kernel_ptr2 = (int8_t *)(kernel_ptr + in_tensor_ch);
117→                    in_val_i8 = __riscv_vle8_v_i8m1(input_ptr2, vl);
118→                    wt_val_i8 = __riscv_vle8_v_i8m1(kernel_ptr2, vl);
119→                    in_val_i16 = __riscv_vsext_vf2(in_val_i8, vl);
120→                    wt_val_i16 = __riscv_vsext_vf2(wt_val_i8, vl);
121→                    in_val_i16 = __riscv_vadd(in_val_i16, in_offset, vl);
122→                    acc_i32 = __riscv_vwmacc(acc_i32, in_val_i16, wt_val_i16, vl);
123→
124→                    if((in_tensor_dim_x - in_x) >= 3)
125→                    {
126→                        input_ptr2 = (int8_t *)(input_ptr + in_tensor_ch * 2);
127→                        kernel_ptr2 = (int8_t *)(kernel_ptr + in_tensor_ch * 2);
128→                        in_val_i8 = __riscv_vle8_v_i8m1(input_ptr2, vl);
129→                        wt_val_i8 = __riscv_vle8_v_i8m1(kernel_ptr2, vl);
130→                        in_val_i16 = __riscv_vsext_vf2(in_val_i8, vl);
131→                        wt_val_i16 = __riscv_vsext_vf2(wt_val_i8, vl);
132→                        in_val_i16 = __riscv_vadd(in_val_i16, in_offset, vl);
133→                        acc_i32 = __riscv_vwmacc(acc_i32, in_val_i16, wt_val_i16, vl);
134→                    }
135→
136→                    input_ptr  += (in_tensor_ch * in_tensor_dim_x);
137→                    kernel_ptr += (in_tensor_ch * 3);
138→                }
139→
140→                //requantization
141→                vint64m8_t out_i64;
142→                vint32m4_t out_scale_i32, out_shift_i32, out_i32;
143→                vuint32m4_t out_shift_u32;
144→                vint16m2_t out_i16;
145→                vint8m1_t out_i8;
146→                out_scale_i32 = __riscv_vle32_v_i32m4(out_scale_ptr, vl);
147→                out_shift_i32 = __riscv_vle32_v_i32m4(out_shift_ptr, vl);
148→                out_shift_i32 = __riscv_vrsub(out_shift_i32, 30, vl);
149→                out_shift_u32 = __riscv_vreinterpret_v_i32m4_u32m4(out_shift_i32);
150→
151→                out_i64 = __riscv_vwmul(acc_i32, out_scale_i32, vl);
152→                out_i32 = __riscv_vnsra(out_i64, out_shift_u32, vl);
153→                out_i32 = __riscv_vssra(out_i32, 1, __RISCV_VXRM_RNU, vl);
154→
155→                out_i32 = __riscv_vadd(out_i32, out_offset, vl);
156→                out_i32 = __riscv_vmax(out_i32, act_min, vl);
157→                out_i32 = __riscv_vmin(out_i32, act_max, vl);
158→
159→                out_i16 = __riscv_vnsra(out_i32, 0, vl);
160→                out_i8  = __riscv_vnsra(out_i16, 0, vl);
161→                __riscv_vse8(out_tensor, out_i8, vl);
162→
163→                rest_in_ch -= vl;
164→                out_tensor += vl;
165→            }
166→        }
167→    }
168→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ELEN64)
169→    long vl;
170→
171→    for(long in_y = -pad_y, out_y = 0; out_y < out_tensor_dim_y; in_y += stride_y, out_y++)
172→    {
173→        long ker_y_start = MAX(0, -in_y);
174→        for(long in_x = -pad_x, out_x = 0; out_x < out_tensor_dim_x; in_x += stride_x, out_x++)
175→        {
176→            long cur_ch = 0;
177→            long ker_x_start = MAX(0, -in_x);
178→
179→            long rest_in_ch = in_tensor_ch;
180→            for(; cur_ch < in_tensor_ch; cur_ch += vl)
181→            {
182→                int32_t *bias_ptr = (int32_t *)&bias[cur_ch];
183→                int32_t *out_shift_ptr = (int32_t *)&out_shift[cur_ch];
184→                int32_t *out_scale_ptr = (int32_t *)&out_scale[cur_ch];
185→                NDS_VEC_VSETVLI(vl, rest_in_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
186→                if (bias != NULL)
187→                {
188→                    NDS_VEC_VLE32_V(NDS_VEC_V0, bias_ptr);
189→                }
190→                else
191→                {
192→                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
193→                }
194→
195→                const int8_t *input_ptr  = in_tensor + (in_y + ker_y_start) * (in_tensor_ch * in_tensor_dim_x) + in_x * in_tensor_ch + cur_ch;
196→                const int8_t *kernel_ptr = ker_weight + ker_y_start * (in_tensor_ch * 3) + cur_ch;
197→
198→                NDS_VEC_VSETVLI(vl, rest_in_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
199→                for(long ker_y = ker_y_start; ker_y < MIN(3, in_tensor_dim_y - in_y); ++ker_y)
200→                {
201→                    if(ker_x_start == 0)
202→                    {
203→                        NDS_VEC_VLE8_V(NDS_VEC_V16, input_ptr);
204→                        NDS_VEC_VLE8_V(NDS_VEC_V20, kernel_ptr);
205→                        NDS_VEC_VSEXT_VF2(NDS_VEC_V8, NDS_VEC_V16);
206→                        NDS_VEC_VSEXT_VF2(NDS_VEC_V12, NDS_VEC_V20);
207→                        NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, in_offset);
208→                        NDS_VEC_VWMACC_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V12);
209→                    }
210→
211→                    int8_t *input_ptr2 = (int8_t *)(input_ptr + in_tensor_ch);
212→                    int8_t *kernel_ptr2 = (int8_t *)(kernel_ptr + in_tensor_ch);
213→                    NDS_VEC_VLE8_V(NDS_VEC_V16, input_ptr2);
214→                    NDS_VEC_VLE8_V(NDS_VEC_V20, kernel_ptr2);
215→                    NDS_VEC_VSEXT_VF2(NDS_VEC_V8, NDS_VEC_V16);
216→                    NDS_VEC_VSEXT_VF2(NDS_VEC_V12, NDS_VEC_V20);
217→                    NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, in_offset);
218→                    NDS_VEC_VWMACC_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V12);
219→
220→                    if((in_tensor_dim_x - in_x) >= 3)
221→                    {
222→                        input_ptr2 = (int8_t *)(input_ptr + in_tensor_ch * 2);
223→                        kernel_ptr2 = (int8_t *)(kernel_ptr + in_tensor_ch * 2);
224→                        NDS_VEC_VLE8_V(NDS_VEC_V16, input_ptr2);
225→                        NDS_VEC_VLE8_V(NDS_VEC_V20, kernel_ptr2);
226→                        NDS_VEC_VSEXT_VF2(NDS_VEC_V8, NDS_VEC_V16);
227→                        NDS_VEC_VSEXT_VF2(NDS_VEC_V12, NDS_VEC_V20);
228→                        NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, in_offset);
229→                        NDS_VEC_VWMACC_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V12);
230→                    }
231→
232→                    input_ptr  += (in_tensor_ch * in_tensor_dim_x);
233→                    kernel_ptr += (in_tensor_ch * 3);
234→                }
235→
236→                //requantization
237→                // part-1
238→                long vl2;
239→                NDS_VEC_VSETVLI(vl, rest_in_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
240→                NDS_VEC_VLE32_V(NDS_VEC_V8, out_scale_ptr);
241→                NDS_VEC_VLE32_V(NDS_VEC_V16, out_shift_ptr);
242→                NDS_VEC_VRSUB_VX(NDS_VEC_V16, NDS_VEC_V16, 30);
243→
244→                NDS_VEC_VSETVLI(vl2, rest_in_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
245→                NDS_VEC_VWMUL_VV(NDS_VEC_V24, NDS_VEC_V0, NDS_VEC_V8);
246→                NDS_VEC_VNSRA_WV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V16);
247→                NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);
248→
249→                NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
250→                NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);

